                                <label>Related Incidents</label>
                                <input
                                    type="number"
                                    name="related_incidents"
                                    value={newEvent.related_incidents}
                                    placeholder="0"
                                    onChange={(e) => {
                                        const value = e.target.value;
                                        handleNewEventFieldChange('related_incidents', value === '' ? '' : parseInt(value, 10));
