        startDateTime: '',
        endDateTime: '',
        alertLevel: '',
        category: '',
        general_weather: '',
        deployment: 'Draft',
        provinces: [],
        sendToAllUsers: false,
        reportLink: '',
        trackPositions: '',
        intensity: '',
        related_incidents: 0,
        remark_related_incidents: '',
        casualties: 0,
        remark_casualties: '',
        power_status: '',
        remark_power_status: '',
        communication_lines: '',
        remark_communication_lines: '',
        damage_facilities: '',
        remark_damage_facilities: '',
        work_suspension: false,
        remark_work_suspension: '',
        assistance_provided: '',
        remark_assistance_provided: '',
        imageUrl: '',
        status: 'pending',
        rejectionReason: ''
